// Package dbutil provides database connection and maintenance utilities for the
// kapow data pipeline tool.
package dbutil

import (
	"context"
	"fmt"

	"github.com/jackc/pgx/v5/pgxpool"
)

// Connect establishes a connection pool to the PostgreSQL database at the given
// DSN. It pings the database to verify connectivity before returning.
//
// TODO: Add retry logic with exponential backoff (similar to api/internal/db).
func Connect(ctx context.Context, databaseURL string) (*pgxpool.Pool, error) {
	pool, err := pgxpool.New(ctx, databaseURL)
	if err != nil {
		return nil, fmt.Errorf("dbutil: connect: %w", err)
	}

	if err := pool.Ping(ctx); err != nil {
		pool.Close()
		return nil, fmt.Errorf("dbutil: ping: %w", err)
	}

	return pool, nil
}

// RefreshMaterializedViews refreshes all materialized views used by the search
// engine. Should be called after a full import run completes.
//
// TODO: Discover and refresh all materialized views in the search_base schema.
func RefreshMaterializedViews(ctx context.Context, pool *pgxpool.Pool) error {
	// Placeholder — will be implemented when import pipelines land.
	_ = ctx
	_ = pool
	return nil
}

// Package fetch provides an HTTP fetcher with local file caching for
// downloading data source files used by the kapow import pipelines.
package fetch

// Fetcher downloads and caches source data files. It stores downloaded files
// in a local cache directory to avoid redundant downloads across runs.
//
// TODO: Implement HTTP download with ETag/Last-Modified caching, progress
// reporting, and archive extraction (ZIP, CSV.gz).
type Fetcher struct {
	cacheDir string
}

// New creates a Fetcher that stores cached downloads in the given directory.
func New(cacheDir string) *Fetcher {
	return &Fetcher{cacheDir: cacheDir}
}

// CacheDir returns the directory used for cached downloads.
func (f *Fetcher) CacheDir() string {
	return f.cacheDir
}

