+		{"RESTRICTED + anon", VisibilityRestricted, false, false},
+		{"RESTRICTED + auth", VisibilityRestricted, true, true},
+		{"HIDDEN + anon", VisibilityHidden, false, false},
+		{"HIDDEN + auth", VisibilityHidden, true, false},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.name, func(t *testing.T) {
+			d := FieldDescriptor{Visibility: tt.visibility}
+			got := IsFieldVisible(d, tt.authenticated)
+			if got != tt.want {
+				t.Errorf("IsFieldVisible(%s, authenticated=%v) = %v, want %v",
+					tt.visibility, tt.authenticated, got, tt.want)
