+package search
+
+import "testing"
+
+func TestIsFieldVisible(t *testing.T) {
+	t.Parallel()
+
+	tests := []struct {
+		name          string
+		visibility    FieldVisibility
+		authenticated bool
+		want          bool
+	}{
+		{"VISIBLE + anon", VisibilityVisible, false, true},
+		{"VISIBLE + auth", VisibilityVisible, true, true},
+		{"RESTRICTED + anon", VisibilityRestricted, false, false},
+		{"RESTRICTED + auth", VisibilityRestricted, true, true},
+		{"HIDDEN + anon", VisibilityHidden, false, false},
+		{"HIDDEN + auth", VisibilityHidden, true, false},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.name, func(t *testing.T) {
+			d := FieldDescriptor{Visibility: tt.visibility}
+			got := IsFieldVisible(d, tt.authenticated)
+			if got != tt.want {
+				t.Errorf("IsFieldVisible(%s, authenticated=%v) = %v, want %v",
+					tt.visibility, tt.authenticated, got, tt.want)
+			}
+		})
+	}
+}
+
+func TestIsFieldSearchable(t *testing.T) {
+	t.Parallel()
+
+	tests := []struct {
+		name          string
+		searchability FieldSearchability
+		authenticated bool
+		want          bool
+	}{
+		{"SEARCHABLE + anon", SearchabilitySearchable, false, true},
+		{"SEARCHABLE + auth", SearchabilitySearchable, true, true},
+		{"RESTRICTED + anon", SearchabilityRestricted, false, false},
+		{"RESTRICTED + auth", SearchabilityRestricted, true, true},
+		{"NOT_SEARCHABLE + anon", SearchabilityNotSearchable, false, false},
+		{"NOT_SEARCHABLE + auth", SearchabilityNotSearchable, true, false},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.name, func(t *testing.T) {
+			d := FieldDescriptor{Searchability: tt.searchability}
+			got := IsFieldSearchable(d, tt.authenticated)
+			if got != tt.want {
+				t.Errorf("IsFieldSearchable(%s, authenticated=%v) = %v, want %v",
+					tt.searchability, tt.authenticated, got, tt.want)
+			}
+		})
+	}
+}
